224	/// Render the group doc, split at \x01 markers, return per-cell line contents
225	/// (indentation and trailing spaces are NOT stripped from the interior; lines
226	/// are split on '\n'; leading spaces of continuation lines are stripped).
227	fn render_split(op: &str, l: isize, rpl: f64, cells: &[String]) -> Vec<Vec<String>> {
228	    let docs: Vec<Doc> = cells
229	        .iter()
230	        .map(|c| beside_op(sized_text(0, "\u{1}"), cell_doc(c)))
231	        .collect();
232	    let g = match op {
233	        "fcat" => fcat(docs),
234	        "fsep" => fsep(docs),
235	        "cat" => cat(docs),
236	        "sep" => sep(docs),
237	        _ => unreachable!(),
238	    };
239	    let out = render_page(l, rpl, &g);
240	    // split into per-cell segments on the marker
241	    let mut per_cell: Vec<String> = Vec::new();
242	    for (i, seg) in out.split('\u{1}').enumerate() {
243	        if i == 0 {
244	            continue; // before first marker (empty or indentation)
245	        }
246	        per_cell.push(seg.to_string());
247	    }
248	    per_cell
249	        .iter()
250	        .map(|seg| {
251	            seg.split('\n')
252	                .map(|l| l.trim_start_matches(' ').trim_end_matches(' ').to_string())
253	                .filter(|l| !l.is_empty())
254	                .collect()
255	        })
256	        .collect()
257	}
