259	fn norm(v: &[Vec<String>]) -> Vec<Vec<String>> {
260	    v.iter()
261	        .map(|c| {
262	            c.iter()
263	                .map(|l| l.trim_end_matches(' ').to_string())
264	                .filter(|l| !l.is_empty())
265	                .collect()
266	        })
267	        .collect()
268	}
